const apiResp = $.steps.searchImageApis.response || {};
const ucResp = $.steps.searchUseCase.response || {};

const apiResults = (apiResp.data || apiResp).results || [];
const ucResults = (ucResp.data || ucResp).results || [];

let context = 'IMAGE GENERATION API RESEARCH:\n';
const sources = [];

apiResults.slice(0, 8).forEach((r, i) => {
  context += 'API SOURCE ' + (i + 1) + ': ' + (r.title || 'Untitled') + '\n';
  context += 'URL: ' + (r.url || '') + '\n';
  context += (r.text || r.snippet || '').slice(0, 1200) + '\n\n';
  sources.push({ title: r.title || 'Source ' + (i + 1), url: r.url || '' });
});

context += '\nUSE-CASE SPECIFIC RESEARCH:\n';
ucResults.slice(0, 5).forEach((r, i) => {
  context += 'UC SOURCE ' + (i + 1) + ': ' + (r.title || 'Untitled') + '\n';
  context += (r.text || r.snippet || '').slice(0, 800) + '\n\n';
  sources.push({ title: r.title || 'UC Source', url: r.url || '' });
});

return { context: context.slice(0, 10000), sources, totalSources: apiResults.length + ucResults.length };

const useCase = $.input.useCase;
const requirements = $.input.requirements || 'No specific requirements';
const research = $.steps.compileResearch.output;

let prompt = 'You are an AI tools expert specializing in image generation. Based on the research provided, recommend the best image generation tools and APIs for the given use case.\n\n';
prompt += 'USE CASE: ' + useCase + '\n';
prompt += 'REQUIREMENTS: ' + requirements + '\n\n';
prompt += 'RESEARCH DATA:\n' + research.context + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Recommend the top 3-5 image generation tools/APIs\n';
prompt += '- Compare pricing, quality, speed, and ease of integration\n';
prompt += '- Highlight which tool is best for the specific use case\n';
prompt += '- Include API access details and free tier availability\n';
prompt += '- Note any limitations or caveats\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "topRecommendation": "name of the best tool for this use case",\n';
prompt += '  "summary": "2-3 sentence overview",\n';
prompt += '  "tools": [\n';
prompt += '    {\n';
prompt += '      "name": "tool name",\n';
prompt += '      "description": "what it does",\n';
prompt += '      "bestFor": "ideal use case",\n';
prompt += '      "pricing": "pricing info",\n';
prompt += '      "apiAccess": true,\n';
prompt += '      "freeTier": true,\n';
prompt += '      "quality": "high|medium|low",\n';
prompt += '      "speed": "fast|medium|slow",\n';
prompt += '      "pros": ["pro1", "pro2"],\n';
prompt += '      "cons": ["con1"]\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "comparisonNotes": ["note1", "note2"],\n';
prompt += '  "quickStart": "recommended first step to get started"\n';
prompt += '}';
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { topRecommendation: 'See analysis', summary: raw, tools: [], comparisonNotes: [], quickStart: '' }; }

const ai = $.steps.parseAI.output;
const useCase = $.input.useCase;
const sources = $.steps.compileResearch.output.sources;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Image Generation Tool Recommendations', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Use Case:* ' + useCase } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Top Pick:*\n' + (ai.topRecommendation || 'N/A') },
  { type: 'mrkdwn', text: '*Tools Compared:*\n' + (ai.tools ? ai.tools.length : 0) }
] });
blocks.push({ type: 'divider' });

const summary = (ai.summary || 'No summary.').slice(0, 1800);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Overview:*\n' + summary } });

if (ai.tools && ai.tools.length > 0) {
  blocks.push({ type: 'divider' });
  ai.tools.slice(0, 5).forEach((tool, i) => {
    let toolText = '*' + (i + 1) + '. ' + tool.name + '*';
    if (tool.bestFor) toolText += '\n_Best for: ' + tool.bestFor + '_';
    if (tool.pricing) toolText += '\nPricing: ' + tool.pricing;
    const badges = [];
    if (tool.apiAccess) badges.push('API');
    if (tool.freeTier) badges.push('Free Tier');
    if (tool.quality) badges.push('Quality: ' + tool.quality);
    if (tool.speed) badges.push('Speed: ' + tool.speed);
    if (badges.length > 0) toolText += '\n' + badges.join(' | ');
    if (tool.pros && tool.pros.length > 0) toolText += '\nPros: ' + tool.pros.slice(0, 3).join(', ');
    if (tool.cons && tool.cons.length > 0) toolText += '\nCons: ' + tool.cons.slice(0, 2).join(', ');
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: toolText.slice(0, 1800) } });
  });
}

if (ai.quickStart) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Quick Start:*\n' + ai.quickStart.slice(0, 800) } });
}

if (ai.comparisonNotes && ai.comparisonNotes.length > 0) {
  let noteText = ai.comparisonNotes.slice(0, 3).join(' | ');
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: noteText.slice(0, 1800) }] });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Exa Search + Claude AI' }] });

const fallbackText = 'Image Gen Tools for ' + useCase + ': Top pick = ' + (ai.topRecommendation || 'N/A');
return { blocks, fallbackText };
